props.extensibilityCode:
// Tabs controladas com analytics
const [value, setValue] = useState('overview');

<Tabs
  value={value}
  onValueChange={(next) => {
    track('tab_change', {
      component: 'tabs',
      label: tabs.find((t) => t.value === next)?.label,
      index: tabs.findIndex((t) => t.value === next),
      total: tabs.length,
    });
    setValue(next);
  }}
>
  <TabsList aria-label="Seções do componente">
    {tabs.map((t) => (
      <TabsTrigger key={t.value} value={t.value}>{t.label}</TabsTrigger>
    ))}
  </TabsList>
  {tabs.map((t) => (
    <TabsContent key={t.value} value={t.value}>{t.content}</TabsContent>
  ))}
</Tabs>

tokens.customizationCode:
/* Altura customizada do TabsList */
[data-slot="tabs-list"] {
  height: 2.5rem;
}

/* Cor customizada da linha (variant line) */
.tabs-brand [data-slot="tabs-list"][data-variant="line"] [data-slot="tabs-trigger"]:after {
  background: hsl(220 90% 50%);
}

